import{c as a,bM as e,bh as r,bk as d,k as l,W as h,am as n}from"./chunks/framework.DXtQZ1HH.js";const g=JSON.parse('{"title":"空间","description":"","frontmatter":{"order":3},"headers":[],"relativePath":"地图/北俱芦洲/空间.md","filePath":"地图/北俱芦洲/空间.md","lastUpdated":1779731263000}'),i={name:"地图/北俱芦洲/空间.md"};function s(o,t,b,c,p,m){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="空间" tabindex="-1">空间 <a class="header-anchor" href="#空间" aria-label="Permalink to “空间”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">缠星藻</td><td style="text-align:center;">青铜石</td><td style="text-align:center;">镜魂丝</td></tr></tbody></table><h2 id="蜃楼城" tabindex="-1">蜃楼城 <a class="header-anchor" href="#蜃楼城" aria-label="Permalink to “蜃楼城”">​</a></h2><h3 id="独角兕大王" tabindex="-1">独角兕大王 <a class="header-anchor" href="#独角兕大王" aria-label="Permalink to “独角兕大王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>霸枪连刺：举起丈二长的钢枪横扫周身后，向前方连刺三下。</td></tr><tr><td>诸牛听令：长枪往地上一立，召唤两头青牛，从两侧狂奔而出。</td></tr><tr><td>金钢琢：召唤金钢琢参与战斗</td></tr><tr><td>金刚琢撞击玩家，玩家被撞后将有短暂晕眩</td></tr><tr><td>金刚琢略微变大套向玩家，玩家被套住后，被金刚琢夺取全部装备（外观消失并且属性降低），打破金刚琢或一分钟后状态解除</td></tr><tr><td>金刚琢变大后出现在玩家上方，释放兵器雨砸向玩家</td></tr></tbody></table><p>掉落道具：帝空防具制作书</p><h2 id="幻境阁" tabindex="-1">幻境阁 <a class="header-anchor" href="#幻境阁" aria-label="Permalink to “幻境阁”">​</a></h2><h3 id="场景" tabindex="-1">场景 <a class="header-anchor" href="#场景" aria-label="Permalink to “场景”">​</a></h3><p>幻境阁中央的八卦阵代表<strong>你所处的位置</strong>。</p><p>我们以进地图的位置为<strong>起点1</strong>顺时针编号，左右两侧，有八卦阵的为+1，没有的为-1</p><p>在1时，选-1会去到3（如图所示为左侧）</p><img src="'+l+'" alt="幻境阁场景" style="zoom:50%;"><div class="tip custom-block"><p class="custom-block-title">结论</p><p>Tips：进图之后走不亮，然后一直走亮到<strong>6</strong></p></div><p>当你<strong>处于6</strong>时</p><p>选+1为<strong>主线</strong>，百眼魔君（一心法制作书）如图所示为左侧</p><p>选-1为<strong>隐藏</strong>，盘丝大仙（二心法制作书）如图所示为右侧</p><img src="'+h+'" alt="幻境阁隐藏" style="zoom:50%;"><h3 id="百眼魔君" tabindex="-1">百眼魔君 <a class="header-anchor" href="#百眼魔君" aria-label="Permalink to “百眼魔君”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>双剑连舞：边快速前进，边挥舞手中的双剑连续攻击前方的玩家</td></tr><tr><td>百眼金光：露出胸口的眼睛向前射出金光（细长型的子弹特效），中招后将被禁锢</td></tr><tr><td>千眼金光：双臂齐抬，正过身来，胸口的眼睛向多个方向射出金光，中招后将被禁锢</td></tr><tr><td>妖幻之镜：在屏幕最左侧和最右侧各召唤一面镜子，该镜子会反射BOSS的千眼金光</td></tr><tr><td>幻惑毒烟：释放黄色的毒烟迷惑玩家的心智。毒烟会在场上持续一段时间，被毒烟笼罩时将无法使用技能，并持续受到伤害</td></tr></tbody></table><p>掉落道具：帝空武器制作书（第一心法）</p><h2 id="幻境阁隐藏" tabindex="-1">幻境阁隐藏 <a class="header-anchor" href="#幻境阁隐藏" aria-label="Permalink to “幻境阁隐藏”">​</a></h2><p>进入方式详情查看<a href="./空间.html#场景">幻境阁场景</a></p><h3 id="盘丝大仙" tabindex="-1">盘丝大仙 <a class="header-anchor" href="#盘丝大仙" aria-label="Permalink to “盘丝大仙”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>短剑连击：使用手中的剑连续攻击前方的玩家</td></tr><tr><td>玄丝乱舞：拉丝飞出屏幕顶部，并从玩家正上方拉丝落下，对玩家进行多段攻击</td></tr><tr><td>束缚之丝：往玩家方向发射蛛丝，将玩家包裹，被射中后将无法行动</td></tr><tr><td>藏身入镜：牵丝飞至自己的镜子，渐隐，藏身到镜子中一段时间</td></tr></tbody></table><p>掉落道具：帝空武器制作书（第二心法）</p><h2 id="壶中洞天" tabindex="-1">壶中洞天 <a class="header-anchor" href="#壶中洞天" aria-label="Permalink to “壶中洞天”">​</a></h2><h3 id="空间祖巫" tabindex="-1">空间祖巫 <a class="header-anchor" href="#空间祖巫" aria-label="Permalink to “空间祖巫”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>混沌漩涡：从手中生成红白的螺旋球，射向玩家</td></tr><tr><td>虚无空间：在玩家所在位置召唤一个黑球，慢慢变大变成黑洞，若玩家没有在黑洞最终形成时逃离，将会被吸入虚无空间（在虚无空间中有4个追魂使者，玩家将其消灭才可离开，虚无空间中玩家无法回血回魔、使用坐骑）</td></tr><tr><td>虚空死魂：召唤一个传送门，传送门每隔10秒会召唤一追魂使者，传送门可被破坏</td></tr><tr><td>虚空暗影：在地面出现一个连接虚空的黑洞，玩家若站在上方超过1秒，则会出现黑暗的触手将其缠绕</td></tr><tr><td>空间移动：瞬间移动到远离玩家的位置</td></tr></tbody></table><p>掉落道具：帝空扳指制作书</p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="帝空御魔圈" tabindex="-1">帝空御魔圈 <a class="header-anchor" href="#帝空御魔圈" aria-label="Permalink to “帝空御魔圈”">​</a></h3><img src="'+n+'" alt="帝空御魔圈" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">6~9</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">4~5</td></tr></tbody></table>',34)])])}const _=a(i,[["render",s]]);export{g as __pageData,_ as default};
